# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import json
import boto3
import logging
from datetime import datetime
from botocore.exceptions import ClientError

logger = logging.getLogger()
logger.setLevel(logging.INFO)

sns_client = boto3.client('sns')

NOTIFICATION_TYPES = {
    'alert': {
        'subject_prefix': '[ALERT]',
        'default_priority': 'high',
    },
    'info': {
        'subject_prefix': '[INFO]',
        'default_priority': 'low',
    },
    'warning': {
        'subject_prefix': '[WARNING]',
        'default_priority': 'medium',
    },
    'critical': {
        'subject_prefix': '[CRITICAL]',
        'default_priority': 'critical',
    },
    'transactional': {
        'subject_prefix': '[TRANSACTION]',
        'default_priority': 'medium',
    },
}


def lambda_handler(event, context):
    """
    Main Lambda handler for publishing messages to SNS topics.
    
    Expected event structure:
    {
        "topic_arn": "arn:aws:sns:region:account-id:topic-name",
        "message": "Your message content here",
        "subject": "Optional subject line",
        "notification_type": "alert|info|warning|critical|transactional",
        "attributes": {
            "key1": "value1",
            "key2": "value2"
        },
        "batch_messages": [
            {
                "topic_arn": "arn:aws:sns:...",
                "message": "Message 1",
                "subject": "Subject 1",
                "notification_type": "info"
            }
        ]
    }
    """
    logger.info(f"Received event: {json.dumps(event)}")
    
    try:
        # Check if this is a batch request
        if 'batch_messages' in event and isinstance(event['batch_messages'], list):
            return handle_batch_publish(event['batch_messages'])
        
        # Single message publish
        return handle_single_publish(event)
    
    except KeyError as e:
        error_msg = f"Missing required field: {str(e)}"
        logger.error(error_msg)
        return build_response(400, {'error': error_msg})
    
    except ClientError as e:
        error_msg = f"AWS SNS error: {e.response['Error']['Message']}"
        logger.error(error_msg)
        return build_response(500, {'error': error_msg})
    
    except Exception as e:
        error_msg = f"Unexpected error: {str(e)}"
        logger.error(error_msg)
        return build_response(500, {'error': error_msg})


def handle_single_publish(event):
    """Handle publishing a single message to an SNS topic."""
    
    # Validate required fields
    topic_arn = event.get('topic_arn')
    message = event.get('message')
    
    if not topic_arn:
        return build_response(400, {'error': 'topic_arn is required'})
    
    if not message:
        return build_response(400, {'error': 'message is required'})
    
    notification_type = event.get('notification_type', 'info')
    subject = event.get('subject', '')
    attributes = event.get('attributes', {})
    
    # Validate notification type
    if notification_type not in NOTIFICATION_TYPES:
        return build_response(400, {
            'error': f"Invalid notification_type: {notification_type}. "
                     f"Valid types: {list(NOTIFICATION_TYPES.keys())}"
        })
    
    # Build and publish the message
    result = publish_message(
        topic_arn=topic_arn,
        message=message,
        subject=subject,
        notification_type=notification_type,
        attributes=attributes
    )
    
    return build_response(200, {
        'message': 'Message published successfully',
        'message_id': result['MessageId'],
        'topic_arn': topic_arn,
        'notification_type': notification_type,
        'timestamp': datetime.utcnow().isoformat()
    })


def handle_batch_publish(batch_messages):
    """Handle publishing multiple messages to SNS topics."""
    
    results = []
    errors = []
    
    for idx, msg_config in enumerate(batch_messages):
        try:
            topic_arn = msg_config.get('topic_arn')
            message = msg_config.get('message')
            
            if not topic_arn or not message:
                errors.append({
                    'index': idx,
                    'error': 'topic_arn and message are required'
                })
                continue
            
            notification_type = msg_config.get('notification_type', 'info')
            subject = msg_config.get('subject', '')
            attributes = msg_config.get('attributes', {})
            
            if notification_type not in NOTIFICATION_TYPES:
                errors.append({
                    'index': idx,
                    'error': f"Invalid notification_type: {notification_type}"
                })
                continue
            
            result = publish_message(
                topic_arn=topic_arn,
                message=message,
                subject=subject,
                notification_type=notification_type,
                attributes=attributes
            )
            
            results.append({
                'index': idx,
                'message_id': result['MessageId'],
                'topic_arn': topic_arn,
                'status': 'success'
            })
        
        except ClientError as e:
            errors.append({
                'index': idx,
                'error': e.response['Error']['Message']
            })
        except Exception as e:
            errors.append({
                'index': idx,
                'error': str(e)
            })
    
    status_code = 200 if not errors else 207  # 207 Multi-Status
    
    return build_response(status_code, {
        'message': f'Batch publish completed. {len(results)} succeeded, {len(errors)} failed.',
        'successful': results,
        'failed': errors,
        'timestamp': datetime.utcnow().isoformat()
    })


def publish_message(topic_arn, message, subject, notification_type, attributes):
    """
    Publish a message to an SNS topic with proper formatting and attributes.
    """
    
    type_config = NOTIFICATION_TYPES[notification_type]
    
    # Build subject with prefix
    if subject:
        full_subject = f"{type_config['subject_prefix']} {subject}"
    else:
        full_subject = f"{type_config['subject_prefix']} Event Notification"
    
    # Truncate subject to SNS limit (100 characters)
    full_subject = full_subject[:100]
    
    # Build structured message for different protocols
    structured_message = build_structured_message(
        message=message,
        notification_type=notification_type,
        subject=full_subject
    )
    
    # Build message attributes
    message_attributes = build_message_attributes(
        notification_type=notification_type,
        priority=type_config['default_priority'],
        custom_attributes=attributes
    )
    
    # Publish to SNS
    publish_params = {
        'TopicArn': topic_arn,
        'Message': json.dumps(structured_message),
        'Subject': full_subject,
        'MessageStructure': 'json',
        'MessageAttributes': message_attributes
    }
    
    logger.info(f"Publishing message to topic: {topic_arn}, type: {notification_type}")
    
    response = sns_client.publish(**publish_params)
    
    logger.info(f"Message published successfully. MessageId: {response['MessageId']}")
    
    return response


def build_structured_message(message, notification_type, subject):
    """
    Build a structured message for different SNS protocols (email, SMS, Lambda, etc.).
    """
    
    timestamp = datetime.utcnow().isoformat()
    
    # Default message (used for protocols without specific formatting)
    default_message = json.dumps({
        'notification_type': notification_type,
        'subject': subject,
        'message': message,
        'timestamp': timestamp
    })
    
    # Email-specific formatting
    email_message = (
        f"{'=' * 50}\n"
        f"Event Notification System\n"
        f"{'=' * 50}\n\n"
        f"Type: {notification_type.upper()}\n"
        f"Time: {timestamp}\n"
        f"Subject: {subject}\n\n"
        f"{'─' * 50}\n"
        f"Message:\n\n"
        f"{message}\n\n"
        f"{'─' * 50}\n"
        f"This is an automated notification from the Event Notification System.\n"
    )
    
    # SMS-specific formatting (keep it short)
    sms_message = f"[{notification_type.upper()}] {message}"
    if len(sms_message) > 160:
        sms_message = sms_message[:157] + "..."
    
    # Lambda/SQS/HTTP - JSON payload
    lambda_message = json.dumps({
        'notification_type': notification_type,
        'subject': subject,
        'message': message,
        'timestamp': timestamp,
        'source': 'event-notification-system'
    })
    
    return {
        'default': default_message,
        'email': email_message,
        'email-json': lambda_message,
        'sms': sms_message,
        'sqs': lambda_message,
        'lambda': lambda_message,
        'http': lambda_message,
        'https': lambda_message
    }


def build_message_attributes(notification_type, priority, custom_attributes):
    """
    Build SNS message attributes for filtering and routing.
    """
    
    message_attributes = {
        'notification_type': {
            'DataType': 'String',
            'StringValue': notification_type
        },
        'priority': {
            'DataType': 'String',
            'StringValue': priority
        },
        'timestamp': {
            'DataType': 'String',
            'StringValue': datetime.utcnow().isoformat()
        },
        'source': {
            'DataType': 'String',
            'StringValue': 'event-notification-system'
        }
    }
    
    # Add custom attributes
    for key, value in custom_attributes.items():
        if isinstance(value, (int, float)):
            message_attributes[key] = {
                'DataType': 'Number',
                'StringValue': str(value)
            }
        else:
            message_attributes[key] = {
                'DataType': 'String',
                'StringValue': str(value)
            }
    
    return message_attributes


def build_response(status_code, body):
    """Build a standardized API response."""
    return {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'X-Service': 'event-notification-system'
        },
        'body': json.dumps(body, default=str)
    }